// Fastpick: quando o jogador colhe algo (player_harvest já é instantâneo
// no DST), entrega o fruto correspondente direto no inventário dele.
// `source` é o prefab do objeto colhido (ex: berrybush, flower).
//
// Ajuste o mapa abaixo à vontade: source -> { prefab, count }.
function run(context) {
  const t = context.trigger || {};
  const userid = t.userid;
  const source = String(t.source || '').toLowerCase();
  if (!userid) return { skipped: 'no userid' };

  // Mapa colhido -> item entregue. count = quanto dar de bônus.
  const MAP = {
    berrybush:        { prefab: 'berries', count: 1 },
    berrybush2:       { prefab: 'berries', count: 1 },
    berrybush_juicy:  { prefab: 'berries_juicy', count: 1 },
    flower:           { prefab: 'petals', count: 1 },
    flower_evil:      { prefab: 'petals_evil', count: 1 },
    cave_banana_tree: { prefab: 'cave_banana', count: 1 },
    reeds:            { prefab: 'cutreeds', count: 1 },
    grass:            { prefab: 'cutgrass', count: 1 },
    sapling:          { prefab: 'twigs', count: 1 },
    marsh_bush:       { prefab: 'twigs', count: 1 }
  };

  const hit = MAP[source];
  if (!hit) return { skipped: 'source nao mapeado', source };

  context.sendCommand('give_item', { userid: userid, prefab: hit.prefab, count: hit.count });
  return { gave: hit.prefab, count: hit.count, source: source };
}
